const b = $json.body ?? $json;
const data = getWorkflowStaticData('global');
data.last = {
  from: b.From,
  text: String(b.Body ?? '').trim()
};
return [{
  json: {
    ok: true,
    from: data.last.from,
    text: data.last.text
  }
}];

const data = getWorkflowStaticData('global');
const q = (data.last?.text ?? '').toLowerCase();
const from = data.last?.from ?? '';

function parseMoneyFromPrecio(precioStr) {
  const s = String(precioStr ?? '').replace(/\s/g, '');
  const m = s.match(/(?:usd|u\$s|\$)\s*([\d\.]+)/i);
  if (!m) return null;
  const n = parseFloat(m[1].replace(/\./g, '').replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

function parseAmbientes(ambStr) {
  const m = String(ambStr ?? '').match(/(\d+)/);
  return m ? parseInt(m[1], 10) : null;
}

const rows = items.map((i) => i.json);
let hits = [...rows];

if (q.includes('tandil')) {
  hits = hits.filter((r) =>
    String(r.Barrio ?? '')
      .toLowerCase()
      .includes('tandil')
  );
}
if (q.includes('rauch')) {
  hits = hits.filter((r) =>
    String(r.Barrio ?? '')
      .toLowerCase()
      .includes('rauch')
  );
}

const ambMatch = q.match(/(\d+)\s*amb/i);
if (ambMatch) {
  const n = parseInt(ambMatch[1], 10);
  hits = hits.filter((r) => {
    const a = parseAmbientes(r.Ambientes);
    return a === null || a === n;
  });
}

const maxUsd = q.match(
  /(?:hasta|maximo|menos\s*de)\s*(?:usd|u\$s|\$)?\s*([\d\.]+)/i
);
if (maxUsd) {
  const cap = parseFloat(maxUsd[1].replace(/\./g, ''));
  hits = hits.filter((r) => {
    const p = parseMoneyFromPrecio(r.Precio);
    return p === null || p <= cap;
  });
}

hits = hits.slice(0, 3);

const catalog = hits
  .map(
    (r) =>
      'ID ' +
      r.ID +
      ' | ' +
      r.Direccion +
      ' | ' +
      r.Barrio +
      ' | ' +
      r.Precio +
      ' | ' +
      r.Ambientes +
      ' | Caracteristicas: ' +
      r.Caracteristicas +
      ' | Fotos: ' +
      r.Link_Fotos
  )
  .join(String.fromCharCode(10));

const sys =
  'Sos un asesor inmobiliario experto en Tandil y zona. Respondé cordial y breve. Solo usá datos del catálogo. Si no hay suficientes datos, decilo y no inventes.';

const user =
  'Consulta del cliente: ' +
  (data.last?.text || '') +
  String.fromCharCode(10, 10) +
  'Catálogo (hasta 3 opciones):' +
  String.fromCharCode(10) +
  (catalog ||
    '(sin coincidencias con el filtro simple; pedí más detalles o ofrecé ampliar criterios.)');

return [{ json: { from, promptSystem: sys, promptUser: user } }];

const message =
  $json.choices?.[0]?.message?.content ??
  'No pude generar respuesta en este momento.';
const from = $('Filter and Build Prompt').first().json.from;
return [{ json: { reply: message, to: from } }];
